module.exports = function(RED) {
    function LibrariesNode(config) {
        RED.nodes.createNode(this, config);
        var node = this;
        
        // Récupération de l'état des checkboxes (ordre alphabétique)
        node.name = config.name;
        node.arduinoJson = config.arduinoJson;
        node.dfplayer = config.dfplayer;
        node.ds18b20 = config.ds18b20;
        node.eeprom = config.eeprom;
        node.keypad = config.keypad;
        node.lcdI2c = config.lcdI2c;
        node.neoPixel = config.neoPixel;
        node.oneWire = config.oneWire;
        node.rc522 = config.rc522;
        node.rcSwitch = config.rcSwitch;
        node.servo = config.servo;
        node.softwareSerial = config.softwareSerial;
        node.tm1637 = config.tm1637;
        node.wdt = config.wdt;

        node.on('input', function(msg) {
            // 0 input, 0 output
        });
    }
    RED.nodes.registerType("Libraries", LibrariesNode);
};